section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-graphql.json",
  "title": "API GraphQL Design",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "schema_path",
    "dataloader_required",
    "pagination_style",
    "depth_limit",
    "complexity_limit",
    "persisted_queries",
    "introspection_in_prod",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug",
      "minLength": 1
    },
    "schema_path": {
      "type": "string",
      "description": "path to the SDL document (.graphql) \u2014 schema-first",
      "minLength": 1
    },
    "dataloader_required": {
      "type": "boolean",
      "description": "must be true; every relation field uses a loader"
    },
    "pagination_style": {
      "type": "string",
      "description": "relay-cursor|offset|none (must be cursor for >100 items)",
      "minLength": 1
    },
    "depth_limit": {
      "type": "integer",
      "description": "max query depth on public endpoint, conventionally 10"
    },
    "complexity_limit": {
      "type": "integer",
      "description": "max query complexity (cost-weighted)"
    },
    "persisted_queries": {
      "type": "boolean",
      "description": "true for production clients; ad-hoc allowed only in dev"
    },
    "introspection_in_prod": {
      "type": "boolean",
      "description": "false on public endpoints"
    }
  },
  "additionalProperties": false
}
